mapper.select:
SELECT *
FROM pinova.admin_login_session
WHERE token_hash = #{tokenHash}
  AND revoked_at IS NULL
  AND expires_at > #{now}
  AND last_seen_at > #{idleAfter}
LIMIT 1

mapper.update:
UPDATE pinova.admin_login_session
SET last_seen_at = #{now}, updated_at = #{now}, updated_by = account_id
WHERE token_hash = #{tokenHash}
  AND revoked_at IS NULL
  AND expires_at > #{now}
  AND last_seen_at <= #{staleBefore}
